// Resolve LinkedIn URL from the provider response.
// Adjust the field below to match YOUR provider's response shape.
const resp = $json || {};
const linkedin_url = resp.linkedin_url ?? resp.linkedin_profile_url ?? resp.url ?? resp.contact?.linkedin_url ?? resp.profile?.linkedin_url ?? resp.person?.linkedin_url ?? resp.data?.linkedin_url ?? resp.response?.linkedin_url ?? "";

// Carry forward all normalized fields, overriding only the LinkedIn ones.
const n = $('Normalize Signup').item.json;
return {
  ...n,
  linkedin_url: linkedin_url,
  has_linkedin_url: Boolean(linkedin_url)
};
